const content = $input.first().json.content;
const raw = Array.isArray(content)
  ? (content.find(b => b.type === 'text')?.text || '')
  : String(content || '');

// Strip wrapping quotes Claude sometimes adds, then normalise whitespace
let question = raw
  .trim()
  .replace(/^["'""'']|["'""'']$/g, '')
  .trim();

// Ensure it ends with a question mark
if (question && !question.endsWith('?')) {
  question = question + '?';
}

// Hard fallback — should never be needed if Claude follows instructions
if (!question) {
  question = 'Could you tell me a bit more about what you need help with?';
}

// Pull original request fields for the Supabase update
const body = $('Webhook - Receive Request').first().json.body;

return [{
  json: {
    clarification_text: question,
    session_id:         body.session_id  || null,
    user_id:            body.user_id     || null,
    original_message:   body.original_message || '',
    confidence:         body.confidence  || 0,
    top_intents:        body.top_intents || []
  }
}];
